'use client'

import { useDataQuery } from '@dhis2/app-runtime'
import {
    Card,
    Button,
    CircularLoader,
    Divider,
    IconChevronDown24,
    IconChevronUp24,
    IconDownload24,
    IconUpload24,
    IconTable24,
    IconFileDocument24,
    IconFolder24,
    IconVisualizationBar24,
} from '@dhis2/ui'
import { useState, useMemo } from 'react'
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    Legend,
    PieChart,
    Pie,
    Cell,
} from 'recharts'
import GenderDistribution from './GenderDistribution'
import classes from './Home.module.css'

// ———— load thematic areas, programs & projects ————
const metaQuery = {
    currentUser: {
        resource: 'me',
        params: { fields: 'id,name,username,organisationUnits[id]' },
    },
    thematicAreas: {
        resource: 'organisationUnits',
        params: {
            paging: false,
            fields: 'id,name,level,parent[name,id],children[id,name,level]',
            filter: 'level:eq:2',
        },
    },
    programs: {
        resource: 'organisationUnits',
        params: {
            paging: false,
            fields: 'id,name,level,parent[name,id],children[id,name,level]',
            filter: 'level:eq:3',
        },
    },
    projects: {
        resource: 'programs',
        params: {
            paging: false,
            fields: 'id,name,organisationUnits[id,name,level,parent[id,name]]',
        },
    },
}

const COLORS = [
    '#3b82f6',
    '#10b981',
    '#8b5cf6',
    '#f59e0b',
    '#ef4444',
    '#06b6d4',
    '#84cc16',
    '#f97316',
    '#ec4899',
    '#14b8a6',
]

export default function Home() {
    const [showImportLinks, setShowImportLinks] = useState(false)
    const [showExportLinks, setShowExportLinks] = useState(false)
    const [expandedChart, setExpandedChart] = useState(null)

    const { loading: metaLoading, data: metaData } = useDataQuery(metaQuery)

    // Derive project distribution data
    const projectsByThematicArea = useMemo(() => {
        const thematicAreas = metaData?.thematicAreas?.organisationUnits ?? []
        const programs = metaData?.programs?.organisationUnits ?? []
        const projects = metaData?.projects?.programs ?? []

        return thematicAreas.map((area, index) => {
            const areaPrograms = programs.filter(
                (p) => p.parent?.id === area.id
            )
            const areaProgramIds = new Set(areaPrograms.map((p) => p.id))
            // A project belongs to a program if any of its assigned org units is that program
            const areaProjects = projects.filter((proj) =>
                (proj.organisationUnits ?? []).some((ou) =>
                    areaProgramIds.has(ou.id)
                )
            )
            return {
                id: area.id,
                name: area.name,
                programs: areaPrograms.length,
                projects: areaProjects.length,
                color: COLORS[index % COLORS.length],
            }
        })
    }, [metaData])

    const projectsByProgram = useMemo(() => {
        const programs = metaData?.programs?.organisationUnits ?? []
        const projects = metaData?.projects?.programs ?? []

        return programs
            .map((program, index) => {
                const programProjects = projects.filter((proj) =>
                    (proj.organisationUnits ?? []).some(
                        (ou) => ou.id === program.id
                    )
                )
                return {
                    id: program.id,
                    name: program.name,
                    thematicArea: program.parent?.name || 'Unknown',
                    projects: programProjects.length,
                    color: COLORS[index % COLORS.length],
                }
            })
            .filter((p) => p.projects > 0)
            .sort((a, b) => b.projects - a.projects)
    }, [metaData])

    const summaryStats = useMemo(() => {
        const thematicAreas = metaData?.thematicAreas?.organisationUnits ?? []
        const programs = metaData?.programs?.organisationUnits ?? []
        const projects = metaData?.projects?.programs ?? []

        const activeThematicAreas = projectsByThematicArea.filter(
            (a) => a.projects > 0
        ).length

        return {
            totalThematicAreas: thematicAreas.length,
            totalPrograms: programs.length,
            totalProjects: projects.length,
            activeThematicAreas,
            avgProjectsPerProgram:
                programs.length > 0
                    ? (projects.length / programs.length).toFixed(1)
                    : 0,
        }
    }, [metaData, projectsByThematicArea])

    const topProjects = useMemo(() => {
        const projects = metaData?.projects?.programs ?? []
        const programs = metaData?.programs?.organisationUnits ?? []
        const thematicAreas = metaData?.thematicAreas?.organisationUnits ?? []

        return projects.slice(0, 10).map((project) => {
            // Find the first level-3 org unit this project is assigned to
            const assignedOu = (project.organisationUnits ?? []).find((ou) =>
                programs.some((p) => p.id === ou.id)
            )
            const parentProgram = programs.find(
                (p) => p.id === assignedOu?.id
            )
            const parentThematicArea = thematicAreas.find(
                (a) => a.id === parentProgram?.parent?.id
            )
            return {
                id: project.id,
                name: project.name,
                program: parentProgram?.name || 'Unknown',
                thematicArea: parentThematicArea?.name || 'Unknown',
            }
        })
    }, [metaData])

    const BASE_URL = window.location.origin
    const cards = [
        {
            title: 'Import Data',
            description: 'Transfer data into the system.',
            link: `${BASE_URL}/sims-web-import-export/#/import`,
            isExpandable: true,
            type: 'import',
            icon: <IconUpload24 />,
            color: '#4f46e5',
        },
        {
            title: 'Export Data',
            description: 'Transfer data out of the system.',
            link: `${BASE_URL}/sims-web-import-export/#/export`,
            isExpandable: true,
            type: 'export',
            icon: <IconDownload24 />,
            color: '#059669',
        },
        {
            title: 'Forms Programs',
            description: 'Access structured forms for data collection.',
            link: `${BASE_URL}/sims-web-capture/`,
            icon: <IconFileDocument24 />,
            color: '#4f46e5',
        },
        {
            title: 'Spreadsheets Programs',
            description: 'Input and manage data using Excel-like grids.',
            link: `${BASE_URL}/sims-web-aggregate-data-entry/`,
            icon: <IconTable24 />,
            color: '#ea580c',
        },
        {
            title: 'Thematic Areas',
            description: 'View thematic areas',
            link: `${BASE_URL}/sims-web-maintenance/#/list/organisationUnitSection/organisationUnit`,
            icon: <IconFolder24 />,
            color: '#ea580c',
        },
        {
            title: 'Visualize',
            description: 'Interact with visualizations and reports',
            link: `https://metabase-prod-890193357774.us-central1.run.app/`,
            icon: <IconVisualizationBar24 />,
            color: '#ea580c',
            isExternal: true,
        },
    ]

    const importLinks = [
        {
            title: 'Import Spreadsheets Data',
            link: `${BASE_URL}/sims-web-import-export/#/import/data`,
        },
        {
            title: 'Import Forms Data',
            link: `${BASE_URL}/sims-web-import-export/#/import/event`,
        },
        {
            title: 'Import Metadata',
            link: `${BASE_URL}/sims-web-import-export/#/import/metadata`,
        },
    ]

    const exportLinks = [
        {
            title: 'Export Spreadsheets',
            link: `${BASE_URL}/sims-web-import-export/#/export/data`,
        },
        {
            title: 'Export Forms Data',
            link: `${BASE_URL}/sims-web-import-export/#/export/event`,
        },
        {
            title: 'Export Metadata',
            link: `${BASE_URL}/sims-web-import-export/#/export/metadata`,
        },
    ]

    const handleCardClick = (card) => {
        if (card.isExpandable) {
            if (card.type === 'import') {
                setShowImportLinks((prev) => !prev)
                if (showExportLinks) {
                    setShowExportLinks(false)
                }
            } else if (card.type === 'export') {
                setShowExportLinks((prev) => !prev)
                if (showImportLinks) {
                    setShowImportLinks(false)
                }
            }
        } else {
            if (card.isExternal) {
                window.open(card.link, '_blank', 'noopener,noreferrer')
            } else {
                window.location.href = card.link
            }
        }
    }

    // Expanded Chart Modal
    const renderExpandedChart = () => {
        if (!expandedChart) {
            return null
        }

        const chartData =
            expandedChart === 'thematic'
                ? projectsByThematicArea
                : projectsByProgram

        const title =
            expandedChart === 'thematic'
                ? 'Projects by Thematic Area'
                : 'Projects by Program'

        return (
            <div
                className={classes.chartModal}
                onClick={() => setExpandedChart(null)}
            >
                <div
                    className={classes.chartModalContent}
                    onClick={(e) => e.stopPropagation()}
                >
                    <div className={classes.chartModalHeader}>
                        <h3 className={classes.chartModalTitle}>{title}</h3>
                        <Button
                            small
                            secondary
                            onClick={() => setExpandedChart(null)}
                        >
                            Close
                        </Button>
                    </div>
                    <div className={classes.chartModalBody}>
                        <ResponsiveContainer width="100%" height={600}>
                            <BarChart
                                data={chartData}
                                margin={{
                                    top: 20,
                                    right: 30,
                                    left: 20,
                                    bottom: 100,
                                }}
                            >
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis
                                    dataKey="name"
                                    angle={-45}
                                    textAnchor="end"
                                    height={120}
                                    fontSize={12}
                                />
                                <YAxis
                                    label={{
                                        value: 'Number of Projects',
                                        angle: -90,
                                        position: 'insideLeft',
                                    }}
                                    fontSize={12}
                                />
                                <Tooltip
                                    contentStyle={{
                                        backgroundColor: 'white',
                                        border: '1px solid #e2e8f0',
                                        borderRadius: '12px',
                                        boxShadow:
                                            '0 4px 20px rgba(0, 0, 0, 0.1)',
                                    }}
                                />
                                <Legend />
                                <Bar
                                    dataKey="projects"
                                    name="Projects"
                                    fill="#3b82f6"
                                    radius={[4, 4, 0, 0]}
                                />
                                {expandedChart === 'thematic' && (
                                    <Bar
                                        dataKey="programs"
                                        name="Programs"
                                        fill="#10b981"
                                        radius={[4, 4, 0, 0]}
                                    />
                                )}
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className={classes.container}>
            {metaLoading && (
                <div className={classes.loader}>
                    <CircularLoader small />
                </div>
            )}

            {/* Header */}
            <div className={classes.header}>
                <div className={classes.headerContent}>
                    <div className={classes.headerText}>
                        <h1 className={classes.pageTitle}>
                            Welcome back,{' '}
                            {metaData?.currentUser?.name?.split(' ')[0] ||
                                'User'}
                        </h1>
                        <p className={classes.pageSubtitle}>
                            Project distribution overview and insights
                        </p>
                    </div>
                </div>
            </div>

            {/* KPI Stats Row */}
            <div className={classes.statsRow}>
                <div className={classes.statCard}>
                    <div
                        className={classes.statIcon}
                        style={{ background: '#eff6ff', color: '#3b82f6' }}
                    >
                        <IconFolder24 />
                    </div>
                    <div className={classes.statInfo}>
                        <span className={classes.statValue}>
                            {summaryStats.totalProjects}
                        </span>
                        <span className={classes.statLabel}>
                            Total Projects
                        </span>
                    </div>
                </div>
                <div className={classes.statCard}>
                    <div
                        className={classes.statIcon}
                        style={{ background: '#ecfdf5', color: '#10b981' }}
                    >
                        <IconFileDocument24 />
                    </div>
                    <div className={classes.statInfo}>
                        <span className={classes.statValue}>
                            {summaryStats.totalPrograms}
                        </span>
                        <span className={classes.statLabel}>Programs</span>
                    </div>
                </div>
                <div className={classes.statCard}>
                    <div
                        className={classes.statIcon}
                        style={{ background: '#faf5ff', color: '#8b5cf6' }}
                    >
                        <IconVisualizationBar24 />
                    </div>
                    <div className={classes.statInfo}>
                        <span className={classes.statValue}>
                            {summaryStats.totalThematicAreas}
                        </span>
                        <span className={classes.statLabel}>
                            Thematic Areas
                        </span>
                    </div>
                </div>
                <div className={classes.statCard}>
                    <div
                        className={classes.statIcon}
                        style={{ background: '#fff7ed', color: '#f59e0b' }}
                    >
                        <IconTable24 />
                    </div>
                    <div className={classes.statInfo}>
                        <span className={classes.statValue}>
                            {summaryStats.avgProjectsPerProgram}
                        </span>
                        <span className={classes.statLabel}>
                            Avg Projects/Program
                        </span>
                    </div>
                </div>
            </div>

            {/* Main Content */}
            <div className={classes.mainGrid}>
                {/* Project Distribution by Thematic Area */}
                <div className={classes.distributionSection}>
                    <div className={classes.sectionHeader}>
                        <h3 className={classes.sectionTitle}>
                            Project Distribution by Thematic Area
                        </h3>
                        <Button
                            small
                            secondary
                            onClick={() => setExpandedChart('thematic')}
                        >
                            Expand
                        </Button>
                    </div>
                    <div className={classes.chartRow}>
                        <div className={classes.chartPane}>
                            <ResponsiveContainer width="100%" height={350}>
                                <BarChart
                                    data={projectsByThematicArea}
                                    margin={{
                                        top: 20,
                                        right: 30,
                                        left: 20,
                                        bottom: 80,
                                    }}
                                >
                                    <CartesianGrid strokeDasharray="3 3" />
                                    <XAxis
                                        dataKey="name"
                                        angle={-35}
                                        textAnchor="end"
                                        height={90}
                                        fontSize={12}
                                    />
                                    <YAxis fontSize={12} />
                                    <Tooltip
                                        contentStyle={{
                                            backgroundColor: 'white',
                                            border: '1px solid #e2e8f0',
                                            borderRadius: '12px',
                                            boxShadow:
                                                '0 4px 20px rgba(0, 0, 0, 0.1)',
                                        }}
                                    />
                                    <Legend />
                                    <Bar
                                        dataKey="projects"
                                        name="Projects"
                                        fill="#3b82f6"
                                        radius={[4, 4, 0, 0]}
                                    />
                                    <Bar
                                        dataKey="programs"
                                        name="Programs"
                                        fill="#10b981"
                                        radius={[4, 4, 0, 0]}
                                    />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                        <div className={classes.chartPane}>
                            <ResponsiveContainer width="100%" height={350}>
                                <PieChart>
                                    <Pie
                                        data={projectsByThematicArea.filter(
                                            (a) => a.projects > 0
                                        )}
                                        dataKey="projects"
                                        nameKey="name"
                                        cx="50%"
                                        cy="50%"
                                        outerRadius={120}
                                        label={({ name, percent }) =>
                                            `${name} (${(percent * 100).toFixed(0)}%)`
                                        }
                                        labelLine
                                    >
                                        {projectsByThematicArea
                                            .filter((a) => a.projects > 0)
                                            .map((entry, index) => (
                                                <Cell
                                                    key={entry.id}
                                                    fill={
                                                        COLORS[
                                                            index %
                                                                COLORS.length
                                                        ]
                                                    }
                                                />
                                            ))}
                                    </Pie>
                                    <Tooltip />
                                    <Legend />
                                </PieChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>

                {/* Project Distribution by Program */}
                <div className={classes.distributionSection}>
                    <div className={classes.sectionHeader}>
                        <h3 className={classes.sectionTitle}>
                            Project Distribution by Program
                        </h3>
                        <Button
                            small
                            secondary
                            onClick={() => setExpandedChart('program')}
                        >
                            Expand
                        </Button>
                    </div>
                    <div className={classes.chartFull}>
                        <ResponsiveContainer width="100%" height={400}>
                            <BarChart
                                data={projectsByProgram.slice(0, 15)}
                                margin={{
                                    top: 20,
                                    right: 30,
                                    left: 20,
                                    bottom: 100,
                                }}
                            >
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis
                                    dataKey="name"
                                    angle={-45}
                                    textAnchor="end"
                                    height={120}
                                    fontSize={11}
                                />
                                <YAxis
                                    label={{
                                        value: 'Projects',
                                        angle: -90,
                                        position: 'insideLeft',
                                    }}
                                    fontSize={12}
                                />
                                <Tooltip
                                    formatter={(value) => [
                                        `${value} projects`,
                                        `Program`,
                                    ]}
                                    labelFormatter={(label) => label}
                                    contentStyle={{
                                        backgroundColor: 'white',
                                        border: '1px solid #e2e8f0',
                                        borderRadius: '12px',
                                        boxShadow:
                                            '0 4px 20px rgba(0, 0, 0, 0.1)',
                                    }}
                                />
                                <Bar
                                    dataKey="projects"
                                    name="Projects"
                                    radius={[4, 4, 0, 0]}
                                >
                                    {projectsByProgram
                                        .slice(0, 15)
                                        .map((entry, index) => (
                                            <Cell
                                                key={entry.id}
                                                fill={
                                                    COLORS[
                                                        index % COLORS.length
                                                    ]
                                                }
                                            />
                                        ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Gender Distribution Section */}
                <GenderDistribution />

                {/* Thematic Area Breakdown Table */}
                <div className={classes.tableSection}>
                    <div className={classes.sectionHeader}>
                        <h3 className={classes.sectionTitle}>
                            Thematic Area Breakdown
                        </h3>
                    </div>
                    <div className={classes.dataTable}>
                        <div className={classes.tableHeader}>
                            <span className={classes.tableHeaderCell}>
                                Thematic Area
                            </span>
                            <span className={classes.tableHeaderCell}>
                                Programs
                            </span>
                            <span className={classes.tableHeaderCell}>
                                Projects
                            </span>
                            <span className={classes.tableHeaderCell}>
                                Distribution
                            </span>
                        </div>
                        {projectsByThematicArea.map((area) => {
                            const maxProjects = Math.max(
                                ...projectsByThematicArea.map(
                                    (a) => a.projects
                                ),
                                1
                            )
                            const barWidth = (area.projects / maxProjects) * 100
                            return (
                                <div key={area.id} className={classes.tableRow}>
                                    <span className={classes.tableCell}>
                                        <span
                                            className={classes.colorDot}
                                            style={{
                                                backgroundColor: area.color,
                                            }}
                                        />
                                        {area.name}
                                    </span>
                                    <span className={classes.tableCell}>
                                        {area.programs}
                                    </span>
                                    <span
                                        className={`${classes.tableCell} ${classes.tableCellBold}`}
                                    >
                                        {area.projects}
                                    </span>
                                    <span className={classes.tableCell}>
                                        <div className={classes.barContainer}>
                                            <div
                                                className={classes.barFill}
                                                style={{
                                                    width: `${barWidth}%`,
                                                    backgroundColor: area.color,
                                                }}
                                            />
                                        </div>
                                    </span>
                                </div>
                            )
                        })}
                    </div>
                </div>

                {/* Recent Projects List */}
                <div className={classes.projectsListSection}>
                    <div className={classes.sectionHeader}>
                        <h3 className={classes.sectionTitle}>
                            Recent Projects
                        </h3>
                    </div>
                    <div className={classes.projectsList}>
                        {topProjects.map((project) => (
                            <div
                                key={project.id}
                                className={classes.projectItem}
                            >
                                <div className={classes.projectIcon}>
                                    <IconFolder24 />
                                </div>
                                <div className={classes.projectInfo}>
                                    <span className={classes.projectName}>
                                        {project.name}
                                    </span>
                                    <span className={classes.projectMeta}>
                                        {project.program} &middot;{' '}
                                        {project.thematicArea}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Quick Actions */}
                <div className={classes.quickActionsContainer}>
                    <div className={classes.sectionHeader}>
                        <h3 className={classes.sectionTitle}>Quick Actions</h3>
                    </div>
                    <div className={classes.cardGrid}>
                        {cards.map((card) => (
                            <div
                                key={card.title}
                                className={classes.cardWrapper}
                            >
                                <Card className={classes.navCard}>
                                    <div
                                        className={classes.cardContent}
                                        role="button"
                                        tabIndex={0}
                                        onClick={() => handleCardClick(card)}
                                        onKeyDown={(e) => {
                                            if (
                                                e.key === 'Enter' ||
                                                e.key === ' '
                                            ) {
                                                handleCardClick(card)
                                            }
                                        }}
                                        style={{ cursor: 'pointer' }}
                                    >
                                        <div
                                            className={classes.cardIconWrapper}
                                            style={{
                                                backgroundColor: `${card.color}15`,
                                                color: card.color,
                                            }}
                                        >
                                            {card.icon}
                                        </div>
                                        <div
                                            className={classes.cardTextContent}
                                        >
                                            <h3 className={classes.cardTitle}>
                                                {card.title}
                                            </h3>
                                            <p
                                                className={
                                                    classes.cardDescription
                                                }
                                            >
                                                {card.description}
                                            </p>
                                        </div>
                                        {card.isExpandable && (
                                            <div className={classes.expandIcon}>
                                                {(card.type === 'import' &&
                                                    showImportLinks) ||
                                                (card.type === 'export' &&
                                                    showExportLinks) ? (
                                                    <IconChevronUp24 />
                                                ) : (
                                                    <IconChevronDown24 />
                                                )}
                                            </div>
                                        )}
                                    </div>
                                    {card.type === 'import' &&
                                        showImportLinks && (
                                            <div
                                                className={
                                                    classes.expandableContent
                                                }
                                            >
                                                <Divider />
                                                <div
                                                    className={classes.linkGrid}
                                                >
                                                    {importLinks.map((item) => (
                                                        <a
                                                            key={item.title}
                                                            href={item.link}
                                                            className={
                                                                classes.linkItem
                                                            }
                                                        >
                                                            {item.title}
                                                        </a>
                                                    ))}
                                                </div>
                                            </div>
                                        )}
                                    {card.type === 'export' &&
                                        showExportLinks && (
                                            <div
                                                className={
                                                    classes.expandableContent
                                                }
                                            >
                                                <Divider />
                                                <div
                                                    className={classes.linkGrid}
                                                >
                                                    {exportLinks.map((item) => (
                                                        <a
                                                            key={item.title}
                                                            href={item.link}
                                                            className={
                                                                classes.linkItem
                                                            }
                                                        >
                                                            {item.title}
                                                        </a>
                                                    ))}
                                                </div>
                                            </div>
                                        )}
                                </Card>
                            </div>
                        ))}
                    </div>
                </div>
            </div>

            {renderExpandedChart()}
        </div>
    )
}
