'use client'

import { useDataQuery } from '@dhis2/app-runtime'
import {
    CircularLoader,
    SingleSelectField,
    SingleSelectOption,
} from '@dhis2/ui'
import { useState, useMemo } from 'react'
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    Legend,
    PieChart,
    Pie,
    Cell,
} from 'recharts'
import classes from './GenderDistribution.module.css'

// Step 1: Get male/female data element IDs + org unit hierarchy
const metadataQuery = {
    maleElements: {
        resource: 'dataElements',
        params: {
            paging: false,
            fields: 'id,name',
            filter: 'name:ilike:male',
        },
    },
    femaleElements: {
        resource: 'dataElements',
        params: {
            paging: false,
            fields: 'id,name',
            filter: 'name:ilike:female',
        },
    },
    // Programs (tracker) that contain these data elements via programStages
    trackerPrograms: {
        resource: 'programs',
        params: {
            paging: false,
            fields: 'id,name,organisationUnits[id,name,level,parent[id,name]],programStages[id,programStageDataElements[dataElement[id,name]]]',
        },
    },
    thematicAreas: {
        resource: 'organisationUnits',
        params: {
            paging: false,
            fields: 'id,name,children[id]',
            filter: 'level:eq:2',
        },
    },
    programOus: {
        resource: 'organisationUnits',
        params: {
            paging: false,
            fields: 'id,name,parent[id,name],children[id]',
            filter: 'level:eq:3',
        },
    },
}

const MALE_COLOR = '#3b82f6'
const FEMALE_COLOR = '#ec4899'

export default function GenderDistribution() {
    const [viewBy, setViewBy] = useState('thematicArea')
    const { loading, data: metaData, error } = useDataQuery(metadataQuery)

    // Separate truly male vs female data elements
    const { maleElementIds, femaleElementIds } = useMemo(() => {
        if (!metaData) {return { maleElementIds: [], femaleElementIds: [] }}

        const allMale = metaData.maleElements?.dataElements ?? []
        const allFemale = metaData.femaleElements?.dataElements ?? []

        // Male elements: contain "male" but NOT "female"
        const male = allMale.filter(
            (de) => !de.name.toLowerCase().includes('female')
        )

        return {
            maleElementIds: male.map((de) => de.id),
            femaleElementIds: allFemale.map((de) => de.id),
        }
    }, [metaData])

    // Build distribution from tracker program metadata
    // Since these are tracker data elements, we map: dataElement → program → orgUnits → hierarchy
    const distributionData = useMemo(() => {
        if (!metaData) {return []}

        const thematicAreas = metaData.thematicAreas?.organisationUnits ?? []
        const programOus = metaData.programOus?.organisationUnits ?? []
        const trackerPrograms = metaData.trackerPrograms?.programs ?? []

        const maleSet = new Set(maleElementIds)
        const femaleSet = new Set(femaleElementIds)

        // Build org unit lookup maps
        const ouToThematic = {}
        const ouToProgram = {}

        thematicAreas.forEach((ta) => {
            ouToThematic[ta.id] = { id: ta.id, name: ta.name }
            ;(ta.children ?? []).forEach((child) => {
                ouToThematic[child.id] = { id: ta.id, name: ta.name }
            })
        })

        programOus.forEach((prog) => {
            ouToProgram[prog.id] = { id: prog.id, name: prog.name }
            ;(prog.children ?? []).forEach((child) => {
                ouToProgram[child.id] = { id: prog.id, name: prog.name }
            })
            if (prog.parent) {
                ouToThematic[prog.id] = { id: prog.parent.id, name: prog.parent.name }
            }
        })

        const groups = {} // { groupId: { name, male, female } }

        // For each tracker program, find which data elements it contains,
        // then count male/female elements per org unit group
        trackerPrograms.forEach((program) => {
            // Collect all data element IDs in this program
            const programDeIds = new Set()
            ;(program.programStages ?? []).forEach((stage) => {
                ;(stage.programStageDataElements ?? []).forEach((psde) => {
                    if (psde.dataElement) {
                        programDeIds.add(psde.dataElement.id)
                    }
                })
            })

            // Count male/female data elements in this program
            let maleCount = 0
            let femaleCount = 0
            programDeIds.forEach((deId) => {
                if (maleSet.has(deId)) {maleCount++}
                if (femaleSet.has(deId)) {femaleCount++}
            })

            if (maleCount === 0 && femaleCount === 0) {return}

            // Assign counts to each org unit this program is assigned to (level 3 only)
            const level3Ous = (program.organisationUnits ?? []).filter((ou) => ou.level === 3)
            ;level3Ous.forEach((ou) => {
                let group = null

                if (viewBy === 'thematicArea') {
                    group = ouToThematic[ou.id]
                    if (!group && ou.parent) {
                        group = ouToThematic[ou.parent.id] || { id: ou.parent.id, name: ou.parent.name }
                    }
                } else if (viewBy === 'program') {
                    group = ouToProgram[ou.id]
                    if (!group && ou.parent) {
                        group = ouToProgram[ou.parent.id] || { id: ou.parent.id, name: ou.parent.name }
                    }
                } else if (viewBy === 'project') {
                    // In project view, the program itself IS the project
                    group = { id: program.id, name: program.name }
                }

                if (!group) {return}

                if (!groups[group.id]) {
                    groups[group.id] = { name: group.name, male: 0, female: 0 }
                }
                // Avoid double-counting: only add once per program-group combo
            })

            // For project view, just add once per program
            if (viewBy === 'project') {
                if (!groups[program.id]) {
                    groups[program.id] = { name: program.name, male: 0, female: 0 }
                }
                groups[program.id].male += maleCount
                groups[program.id].female += femaleCount
            } else {
                // For thematic/program view, aggregate across org units (level 3 only)
                const seenGroups = new Set()
                ;level3Ous.forEach((ou) => {
                    let group = null
                    if (viewBy === 'thematicArea') {
                        group = ouToThematic[ou.id]
                        if (!group && ou.parent) {
                            group = ouToThematic[ou.parent.id] || { id: ou.parent.id, name: ou.parent.name }
                        }
                    } else if (viewBy === 'program') {
                        group = ouToProgram[ou.id]
                        if (!group && ou.parent) {
                            group = ouToProgram[ou.parent.id] || { id: ou.parent.id, name: ou.parent.name }
                        }
                    }
                    if (!group || seenGroups.has(group.id)) {return}
                    seenGroups.add(group.id)

                    if (!groups[group.id]) {
                        groups[group.id] = { name: group.name, male: 0, female: 0 }
                    }
                    groups[group.id].male += maleCount
                    groups[group.id].female += femaleCount
                })
            }
        })

        return Object.entries(groups)
            .map(([id, g]) => ({
                id,
                name: g.name,
                male: Math.round(g.male),
                female: Math.round(g.female),
                total: Math.round(g.male + g.female),
            }))
            .filter((d) => d.total > 0)
            .sort((a, b) => b.total - a.total)
    }, [metaData, maleElementIds, femaleElementIds, viewBy])

    // Summary totals
    const totals = useMemo(() => {
        return distributionData.reduce(
            (acc, item) => ({
                male: acc.male + item.male,
                female: acc.female + item.female,
                total: acc.total + item.total,
            }),
            { male: 0, female: 0, total: 0 }
        )
    }, [distributionData])

    const pieData = [
        { name: 'Male', value: totals.male, color: MALE_COLOR },
        { name: 'Female', value: totals.female, color: FEMALE_COLOR },
    ]

    if (loading) {
        return (
            <div className={classes.loaderContainer}>
                <CircularLoader small />
                <span>Loading gender distribution data...</span>
            </div>
        )
    }

    if (error) {
        return (
            <div className={classes.errorContainer}>
                <p>Failed to load gender distribution data.</p>
            </div>
        )
    }

    const viewLabel =
        viewBy === 'thematicArea'
            ? 'Thematic Area'
            : viewBy === 'program'
              ? 'Program'
              : 'Project'

    return (
        <div className={classes.genderSection}>
            <div className={classes.sectionHeader}>
                <h3 className={classes.sectionTitle}>
                    Gender Distribution (Aggregated Values)
                </h3>
                <div className={classes.viewSelector}>
                    <SingleSelectField
                        label="View by"
                        selected={viewBy}
                        onChange={({ selected }) => setViewBy(selected)}
                        dense
                    >
                        <SingleSelectOption
                            label="Thematic Area"
                            value="thematicArea"
                        />
                        <SingleSelectOption label="Program" value="program" />
                        <SingleSelectOption label="Project" value="project" />
                    </SingleSelectField>
                </div>
            </div>

            {/* Summary Cards */}
            <div className={classes.genderStats}>
                <div className={classes.genderStatCard}>
                    <div
                        className={classes.genderDot}
                        style={{ background: MALE_COLOR }}
                    />
                    <div className={classes.genderStatInfo}>
                        <span className={classes.genderStatValue}>
                            {totals.male}
                        </span>
                        <span className={classes.genderStatLabel}>
                            Male (Total Value)
                        </span>
                    </div>
                </div>
                <div className={classes.genderStatCard}>
                    <div
                        className={classes.genderDot}
                        style={{ background: FEMALE_COLOR }}
                    />
                    <div className={classes.genderStatInfo}>
                        <span className={classes.genderStatValue}>
                            {totals.female}
                        </span>
                        <span className={classes.genderStatLabel}>
                            Female (Total Value)
                        </span>
                    </div>
                </div>
                <div className={classes.genderStatCard}>
                    <div
                        className={classes.genderDot}
                        style={{ background: '#6b7280' }}
                    />
                    <div className={classes.genderStatInfo}>
                        <span className={classes.genderStatValue}>
                            {totals.total}
                        </span>
                        <span className={classes.genderStatLabel}>
                            Combined Total
                        </span>
                    </div>
                </div>
                <div className={classes.genderStatCard}>
                    <div
                        className={classes.genderDot}
                        style={{ background: '#10b981' }}
                    />
                    <div className={classes.genderStatInfo}>
                        <span className={classes.genderStatValue}>
                            {totals.total > 0
                                ? `${((totals.female / totals.total) * 100).toFixed(1)}%`
                                : '0%'}
                        </span>
                        <span className={classes.genderStatLabel}>
                            Female Ratio
                        </span>
                    </div>
                </div>
            </div>

            {/* Charts Row */}
            <div className={classes.genderChartRow}>
                {/* Bar Chart */}
                <div className={classes.genderChartPane}>
                    <h4 className={classes.chartSubtitle}>
                        By {viewLabel}
                    </h4>
                    <ResponsiveContainer width="100%" height={350}>
                        <BarChart
                            data={distributionData.slice(0, 12)}
                            margin={{
                                top: 20,
                                right: 30,
                                left: 20,
                                bottom: 80,
                            }}
                        >
                            <CartesianGrid strokeDasharray="3 3" />
                            <XAxis
                                dataKey="name"
                                angle={-35}
                                textAnchor="end"
                                height={90}
                                fontSize={11}
                            />
                            <YAxis fontSize={12} />
                            <Tooltip
                                contentStyle={{
                                    backgroundColor: 'white',
                                    border: '1px solid #e2e8f0',
                                    borderRadius: '12px',
                                    boxShadow: '0 4px 20px rgba(0, 0, 0, 0.1)',
                                }}
                            />
                            <Legend />
                            <Bar
                                dataKey="male"
                                name="Male"
                                fill={MALE_COLOR}
                                radius={[4, 4, 0, 0]}
                            />
                            <Bar
                                dataKey="female"
                                name="Female"
                                fill={FEMALE_COLOR}
                                radius={[4, 4, 0, 0]}
                            />
                        </BarChart>
                    </ResponsiveContainer>
                </div>

                {/* Pie Chart */}
                <div className={classes.genderChartPaneSmall}>
                    <h4 className={classes.chartSubtitle}>Overall Split</h4>
                    <ResponsiveContainer width="100%" height={350}>
                        <PieChart>
                            <Pie
                                data={pieData}
                                dataKey="value"
                                nameKey="name"
                                cx="50%"
                                cy="50%"
                                outerRadius={110}
                                label={({ name, percent }) =>
                                    `${name} (${(percent * 100).toFixed(1)}%)`
                                }
                                labelLine
                            >
                                {pieData.map((entry) => (
                                    <Cell
                                        key={entry.name}
                                        fill={entry.color}
                                    />
                                ))}
                            </Pie>
                            <Tooltip />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </div>

            {/* Table */}
            <div className={classes.genderTable}>
                <div className={classes.genderTableHeader}>
                    <span className={classes.genderTableHeaderCell}>
                        {viewLabel}
                    </span>
                    <span className={classes.genderTableHeaderCell}>Male</span>
                    <span className={classes.genderTableHeaderCell}>
                        Female
                    </span>
                    <span className={classes.genderTableHeaderCell}>Total</span>
                    <span className={classes.genderTableHeaderCell}>
                        Female %
                    </span>
                    <span className={classes.genderTableHeaderCell}>
                        Distribution
                    </span>
                </div>
                {distributionData.map((row) => {
                    const femalePercent =
                        row.total > 0
                            ? ((row.female / row.total) * 100).toFixed(1)
                            : '0.0'
                    const maleWidth =
                        row.total > 0 ? (row.male / row.total) * 100 : 0
                    const femaleWidth =
                        row.total > 0 ? (row.female / row.total) * 100 : 0

                    return (
                        <div key={row.id} className={classes.genderTableRow}>
                            <span className={classes.genderTableCell}>
                                {row.name}
                            </span>
                            <span className={classes.genderTableCell}>
                                {row.male}
                            </span>
                            <span className={classes.genderTableCell}>
                                {row.female}
                            </span>
                            <span className={classes.genderTableCell}>
                                {row.total}
                            </span>
                            <span className={classes.genderTableCell}>
                                {femalePercent}%
                            </span>
                            <span className={classes.genderTableCell}>
                                <div className={classes.genderBar}>
                                    <div
                                        className={classes.genderBarMale}
                                        style={{ width: `${maleWidth}%` }}
                                    />
                                    <div
                                        className={classes.genderBarFemale}
                                        style={{ width: `${femaleWidth}%` }}
                                    />
                                </div>
                            </span>
                        </div>
                    )
                })}
            </div>
        </div>
    )
}
